class Solution:
    def sumOfSquares(self, nums):
        n = len(nums)
        divisors = set()
        i = 1
        while i * i <= n:
            if n % i == 0:
                divisors.add(i)
                divisors.add(n // i)
            i += 1
        return sum(nums[d - 1] ** 2 for d in divisors)

